﻿'use client'

import { useCallback, useEffect, useMemo, useRef, useState } from 'react'
import { cn } from '@/lib/utils'

type PriceRangeSliderProps = {
  minLimit: number
  maxLimit: number
  step?: number
  initialMin?: number
  initialMax?: number
  valueMin?: number
  valueMax?: number
  currencyLabel: string
  nameMin?: string
  nameMax?: string
  onChange?: (min: number, max: number) => void
  onCommit?: (min: number, max: number) => void
  compact?: boolean
}

type ActiveThumb = 'min' | 'max' | null

function clamp(value: number, min: number, max: number) {
  return Math.min(max, Math.max(min, value))
}

function roundToStep(value: number, step: number) {
  return Math.round(value / step) * step
}

export function PriceRangeSlider({
  minLimit,
  maxLimit,
  step = 1,
  initialMin,
  initialMax,
  valueMin,
  valueMax,
  currencyLabel,
  nameMin,
  nameMax,
  onChange,
  onCommit,
  compact = false,
}: PriceRangeSliderProps) {
  const trackRef = useRef<HTMLDivElement>(null)
  const minRef = useRef<number>(0)
  const maxRef = useRef<number>(0)
  const [activeThumb, setActiveThumb] = useState<ActiveThumb>(null)

  const safeStep = Math.max(1, Math.floor(step))
  const safeMinLimit = Math.max(0, Math.floor(minLimit))
  const safeMaxLimit = Math.max(safeMinLimit, Math.ceil(maxLimit))
  const isControlled = typeof valueMin === 'number' && typeof valueMax === 'number'

  const [internalMin, setInternalMin] = useState(() => {
    const raw = initialMin ?? safeMinLimit
    return clamp(roundToStep(raw, safeStep), safeMinLimit, safeMaxLimit)
  })
  const [internalMax, setInternalMax] = useState(() => {
    const raw = initialMax ?? safeMaxLimit
    return clamp(roundToStep(raw, safeStep), safeMinLimit, safeMaxLimit)
  })

  const minValue = isControlled
    ? clamp(roundToStep(valueMin as number, safeStep), safeMinLimit, safeMaxLimit)
    : internalMin
  const maxValue = isControlled
    ? clamp(roundToStep(valueMax as number, safeStep), safeMinLimit, safeMaxLimit)
    : internalMax

  minRef.current = minValue
  maxRef.current = maxValue

  useEffect(() => {
    if (minValue <= maxValue) return
    if (isControlled) {
      onChange?.(minValue, minValue)
      return
    }
    setInternalMax(minValue)
  }, [isControlled, minValue, maxValue, onChange])

  const valueRange = Math.max(1, safeMaxLimit - safeMinLimit)

  const minPercent = useMemo(() => {
    return ((minValue - safeMinLimit) / valueRange) * 100
  }, [minValue, safeMinLimit, valueRange])

  const maxPercent = useMemo(() => {
    return ((maxValue - safeMinLimit) / valueRange) * 100
  }, [maxValue, safeMinLimit, valueRange])

  const display = useMemo(() => {
    const minText = `${currencyLabel} ${Math.round(minValue)}`
    const maxText =
      maxValue >= safeMaxLimit
        ? `${currencyLabel} ${Math.round(safeMaxLimit)}+`
        : `${currencyLabel} ${Math.round(maxValue)}`
    return `${minText} - ${maxText}`
  }, [currencyLabel, minValue, maxValue, safeMaxLimit])

  const setValues = useCallback((nextMin: number, nextMax: number) => {
    if (isControlled) {
      onChange?.(nextMin, nextMax)
      return
    }

    setInternalMin(nextMin)
    setInternalMax(nextMax)
    onChange?.(nextMin, nextMax)
  }, [isControlled, onChange])

  const getValueFromClientX = useCallback((clientX: number) => {
    const track = trackRef.current
    if (!track) return minValue
    const rect = track.getBoundingClientRect()
    if (rect.width <= 0) return minValue

    const relative = clamp(clientX - rect.left, 0, rect.width)
    const percent = relative / rect.width
    const raw = safeMinLimit + percent * valueRange
    return clamp(roundToStep(raw, safeStep), safeMinLimit, safeMaxLimit)
  }, [minValue, safeMaxLimit, safeMinLimit, safeStep, valueRange])

  useEffect(() => {
    if (!activeThumb) return

    const handlePointerMove = (event: PointerEvent) => {
      const next = getValueFromClientX(event.clientX)
      const currentMin = minRef.current
      const currentMax = maxRef.current
      if (activeThumb === 'min') {
        const nextMin = clamp(Math.min(next, currentMax), safeMinLimit, safeMaxLimit)
        setValues(nextMin, currentMax)
        return
      }

      const nextMax = clamp(Math.max(next, currentMin), safeMinLimit, safeMaxLimit)
      setValues(currentMin, nextMax)
    }

    const handlePointerUp = () => {
      onCommit?.(minRef.current, maxRef.current)
      setActiveThumb(null)
    }

    window.addEventListener('pointermove', handlePointerMove)
    window.addEventListener('pointerup', handlePointerUp)
    window.addEventListener('pointercancel', handlePointerUp)

    return () => {
      window.removeEventListener('pointermove', handlePointerMove)
      window.removeEventListener('pointerup', handlePointerUp)
      window.removeEventListener('pointercancel', handlePointerUp)
    }
  }, [activeThumb, getValueFromClientX, onCommit, safeMaxLimit, safeMinLimit, setValues])

  const handleKeyDown = (thumb: 'min' | 'max', key: string) => {
    let delta = 0

    if (key === 'ArrowLeft' || key === 'ArrowDown') delta = -safeStep
    if (key === 'ArrowRight' || key === 'ArrowUp') delta = safeStep
    if (key === 'PageDown') delta = -safeStep * 10
    if (key === 'PageUp') delta = safeStep * 10

    if (delta !== 0) {
      if (thumb === 'min') {
        const nextMin = clamp(minValue + delta, safeMinLimit, maxValue)
        setValues(nextMin, maxValue)
        onCommit?.(nextMin, maxValue)
      } else {
        const nextMax = clamp(maxValue + delta, minValue, safeMaxLimit)
        setValues(minValue, nextMax)
        onCommit?.(minValue, nextMax)
      }
      return
    }

    if (key === 'Home') {
      if (thumb === 'min') {
        setValues(safeMinLimit, maxValue)
        onCommit?.(safeMinLimit, maxValue)
      } else {
        setValues(minValue, minValue)
        onCommit?.(minValue, minValue)
      }
      return
    }

    if (key === 'End') {
      if (thumb === 'min') {
        setValues(maxValue, maxValue)
        onCommit?.(maxValue, maxValue)
      } else {
        setValues(minValue, safeMaxLimit)
        onCommit?.(minValue, safeMaxLimit)
      }
    }
  }

  return (
    <div className="w-full">
      <div className={cn('mb-1 flex items-center justify-between gap-2', compact && 'mb-0.5')}>
        <span className={cn('text-xs font-medium text-neutral-500', compact && 'text-[11px]')}>Preço</span>
        <span className={cn('text-xs font-semibold text-neutral-800', compact && 'text-[11px]')} aria-live="polite">
          {display}
        </span>
      </div>

      <div className={cn('relative', compact ? 'h-8' : 'h-10')}>
        <div
          ref={trackRef}
          className="absolute left-0 right-0 top-1/2 h-1 -translate-y-1/2 rounded-full bg-neutral-200"
          style={{ touchAction: 'none' }}
          onPointerDown={event => {
            event.preventDefault()
            const next = getValueFromClientX(event.clientX)
            const distanceToMin = Math.abs(next - minValue)
            const distanceToMax = Math.abs(next - maxValue)

            if (distanceToMin <= distanceToMax) {
              const nextMin = clamp(Math.min(next, maxValue), safeMinLimit, safeMaxLimit)
              setValues(nextMin, maxValue)
              setActiveThumb('min')
            } else {
              const nextMax = clamp(Math.max(next, minValue), safeMinLimit, safeMaxLimit)
              setValues(minValue, nextMax)
              setActiveThumb('max')
            }
          }}
        />

        <div
          className="absolute top-1/2 h-1 -translate-y-1/2 rounded-full bg-brand-500"
          style={{ left: `${minPercent}%`, width: `${Math.max(0, maxPercent - minPercent)}%` }}
          aria-hidden="true"
        />

        <button
          type="button"
          role="slider"
          aria-label="Preço mínimo"
          aria-valuemin={safeMinLimit}
          aria-valuemax={maxValue}
          aria-valuenow={minValue}
          onPointerDown={event => {
            event.preventDefault()
            event.stopPropagation()
            event.currentTarget.setPointerCapture(event.pointerId)
            setActiveThumb('min')
          }}
          onKeyDown={event => handleKeyDown('min', event.key)}
          className={cn(
            'absolute top-1/2 h-5 w-5 -translate-x-1/2 -translate-y-1/2 rounded-full border border-neutral-300 bg-white shadow focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-brand-500/20',
            activeThumb === 'min' ? 'z-30' : 'z-20',
          )}
          style={{ left: `${minPercent}%`, touchAction: 'none' }}
        />

        <button
          type="button"
          role="slider"
          aria-label="Preço máximo"
          aria-valuemin={minValue}
          aria-valuemax={safeMaxLimit}
          aria-valuenow={maxValue}
          onPointerDown={event => {
            event.preventDefault()
            event.stopPropagation()
            event.currentTarget.setPointerCapture(event.pointerId)
            setActiveThumb('max')
          }}
          onKeyDown={event => handleKeyDown('max', event.key)}
          className={cn(
            'absolute top-1/2 h-5 w-5 -translate-x-1/2 -translate-y-1/2 rounded-full border border-neutral-300 bg-white shadow focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-brand-500/20',
            activeThumb === 'max' ? 'z-30' : 'z-20',
          )}
          style={{ left: `${maxPercent}%`, touchAction: 'none' }}
        />
      </div>

      {nameMin ? <input type="hidden" name={nameMin} value={String(minValue)} /> : null}
      {nameMax ? <input type="hidden" name={nameMax} value={String(maxValue)} /> : null}
    </div>
  )
}

type RuntimeCacheEntry<T> = {
  value: T
  expiresAt: number
}

type RuntimeCacheStore = Map<string, RuntimeCacheEntry<unknown>>
type RuntimeCacheInflightStore = Map<string, Promise<unknown>>

declare global {
  // eslint-disable-next-line no-var
  var __muudayRuntimeCache: RuntimeCacheStore | undefined
  // eslint-disable-next-line no-var
  var __muudayRuntimeCacheInflight: RuntimeCacheInflightStore | undefined
}

function getStore() {
  if (!globalThis.__muudayRuntimeCache) {
    globalThis.__muudayRuntimeCache = new Map<string, RuntimeCacheEntry<unknown>>()
  }
  return globalThis.__muudayRuntimeCache
}

function getInflightStore() {
  if (!globalThis.__muudayRuntimeCacheInflight) {
    globalThis.__muudayRuntimeCacheInflight = new Map<string, Promise<unknown>>()
  }
  return globalThis.__muudayRuntimeCacheInflight
}

export async function getCachedRuntimeValue<T>(
  key: string,
  ttlMs: number,
  producer: () => Promise<T>,
): Promise<T> {
  const now = Date.now()
  const store = getStore()
  const inflightStore = getInflightStore()
  const existing = store.get(key)
  if (existing && existing.expiresAt > now) {
    return existing.value as T
  }

  const inflight = inflightStore.get(key)
  if (inflight) {
    return inflight as Promise<T>
  }

  const pending = producer()
    .then(value => {
      store.set(key, { value, expiresAt: Date.now() + ttlMs })
      return value
    })
    .finally(() => {
      inflightStore.delete(key)
    })

  inflightStore.set(key, pending)
  return pending as Promise<T>
}

export function invalidateRuntimeCache(prefix?: string) {
  const store = getStore()
  const inflightStore = getInflightStore()
  if (!prefix) {
    store.clear()
    inflightStore.clear()
    return
  }
  store.forEach((_, key) => {
    if (key.startsWith(prefix)) {
      store.delete(key)
    }
  })
  inflightStore.forEach((_, key) => {
    if (key.startsWith(prefix)) {
      inflightStore.delete(key)
    }
  })
}

import { z } from 'zod'

// Treat empty strings as undefined so optional env vars don't fail .min(1)
const optionalString = z.preprocess((val) => (val === '' ? undefined : val), z.string().min(1).optional())

const envSchema = z.object({
  // Public / client-safe (always required)
  NEXT_PUBLIC_SUPABASE_URL: z.string().url(),
  NEXT_PUBLIC_SUPABASE_ANON_KEY: z.string().min(1),
  NEXT_PUBLIC_APP_URL: z.preprocess((val) => (val === '' ? undefined : val), z.string().url().optional()),

  // Server-only critical (required for core functionality)
  APP_BASE_URL: z.preprocess((val) => (val === '' ? undefined : val), z.string().url().optional()),
  SUPABASE_SERVICE_ROLE_KEY: z.string().min(1),

  // Database (at least one must be configured)
  SUPABASE_DB_POOLER_URL: optionalString,
  SUPABASE_DB_DIRECT_URL: optionalString,
  DATABASE_URL: optionalString,

  // Auth / security
  CRON_SECRET: z.preprocess((val) => (val === '' ? undefined : val), z.string().min(16).optional()),
  SUPABASE_DB_WEBHOOK_SECRET: z.preprocess((val) => (val === '' ? undefined : val), z.string().min(16).optional()),

  // Email
  RESEND_API_KEY: optionalString,

  // Redis / caching
  UPSTASH_REDIS_REST_URL: z.preprocess((val) => (val === '' ? undefined : val), z.string().url().optional()),
  UPSTASH_REDIS_REST_TOKEN: optionalString,

  // Payments (Stripe)
  STRIPE_SECRET_KEY: optionalString,
  NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY: optionalString,
  STRIPE_CONNECT_CLIENT_ID: optionalString,
  STRIPE_WEBHOOK_SECRET: optionalString,
  STRIPE_BR_SECRET_KEY: optionalString,
  NEXT_PUBLIC_STRIPE_BR_PUBLISHABLE_KEY: optionalString,

  // Observability
  SENTRY_DSN: optionalString,
  NEXT_PUBLIC_SENTRY_DSN: optionalString,
  SENTRY_ORG: optionalString,
  SENTRY_PROJECT: optionalString,
  NEXT_PUBLIC_SENTRY_TRACES_SAMPLE_RATE: z.coerce.number().min(0).max(1).default(0.1),

  // Analytics
  NEXT_PUBLIC_POSTHOG_KEY: optionalString,
  NEXT_PUBLIC_POSTHOG_HOST: z.string().url().default('https://us.i.posthog.com'),

  // Video (Agora)
  AGORA_APP_ID: optionalString,
  AGORA_APP_CERTIFICATE: optionalString,

  // OAuth (Calendar sync)
  GOOGLE_CLIENT_ID: optionalString,
  GOOGLE_CLIENT_SECRET: optionalString,
  OUTLOOK_CLIENT_ID: optionalString,
  OUTLOOK_CLIENT_SECRET: optionalString,
  CALENDAR_TOKEN_ENCRYPTION_KEY: optionalString,
  CALENDAR_OAUTH_STATE_SECRET: optionalString,

  // Background jobs
  INNGEST_EVENT_KEY: optionalString,
  INNGEST_SIGNING_KEY: optionalString,

  // Admin audit
  ADMIN_AUDIT_FAIL_ON_ERROR: z.enum(['true', 'false']).default('false'),

  // E2E / testing
  E2E_BASE_URL: z.preprocess((val) => (val === '' ? undefined : val), z.string().url().optional()),
  E2E_USER_EMAIL: z.preprocess((val) => (val === '' ? undefined : val), z.string().email().optional()),
  E2E_USER_PASSWORD: optionalString,
  E2E_PROFESSIONAL_EMAIL: z.preprocess((val) => (val === '' ? undefined : val), z.string().email().optional()),
  E2E_PROFESSIONAL_PASSWORD: optionalString,
  E2E_ADMIN_EMAIL: z.preprocess((val) => (val === '' ? undefined : val), z.string().email().optional()),
  E2E_ADMIN_PASSWORD: optionalString,
})

function validateEnv() {
  const parsed = envSchema.safeParse(process.env)

  if (!parsed.success) {
    const lines = parsed.error.issues.map((issue) => `  - ${issue.path.join('.')}: ${issue.message}`)
    const message = `Invalid or missing environment variables:\n${lines.join('\n')}`

    // In CI, fail hard so we catch misconfigurations early.
    // On Vercel production, log as error but do not crash the Edge runtime.
    if (process.env.CI) {
      throw new Error(message)
    }
    if (process.env.VERCEL_ENV === 'production') {
      console.error(`[env] ${message}`)
    }

    // In local development, warn but do not crash so the dev server can still start
    // eslint-disable-next-line no-console
    console.warn(`[env] ${message}`)
  }

  // Cross-field validation: ensure at least one DB connection string is present
  const dbUrl = process.env.DATABASE_URL || process.env.SUPABASE_DB_POOLER_URL || process.env.SUPABASE_DB_DIRECT_URL
  if (!dbUrl && process.env.CI) {
    throw new Error(
      'Missing database connection string. Set one of: DATABASE_URL, SUPABASE_DB_POOLER_URL, SUPABASE_DB_DIRECT_URL',
    )
  }
  if (!dbUrl && process.env.VERCEL_ENV === 'production') {
    console.error('Missing database connection string. Set one of: DATABASE_URL, SUPABASE_DB_POOLER_URL, SUPABASE_DB_DIRECT_URL')
  }

  return parsed.success ? parsed.data : (process.env as unknown as z.infer<typeof envSchema>)
}

export const env = validateEnv()

import 'server-only'

import * as Sentry from '@sentry/nextjs'
import { Ratelimit } from '@upstash/ratelimit'
import { Redis } from '@upstash/redis'

type RateLimitOptions = {
  key: string
  limit: number
  windowSeconds: number
}

export type RateLimitResult = {
  allowed: boolean
  limit: number
  remaining: number
  retryAfterSeconds: number
  source: 'upstash' | 'memory'
}

const MEMORY_FALLBACK_ALERT_INTERVAL_MS = 15 * 60 * 1000

let redis: Redis | null = null
const limiters = new Map<string, Ratelimit>()

function getRedis(): Redis | null {
  if (redis) return redis
  const url = process.env.UPSTASH_REDIS_REST_URL
  const token = process.env.UPSTASH_REDIS_REST_TOKEN
  if (!url || !token) return null
  redis = new Redis({ url, token })
  return redis
}

function getLimiter(limit: number, windowSeconds: number): Ratelimit | null {
  const r = getRedis()
  if (!r) return null

  const cacheKey = `${limit}:${windowSeconds}`
  let limiter = limiters.get(cacheKey)
  if (!limiter) {
    limiter = new Ratelimit({
      redis: r,
      limiter: Ratelimit.slidingWindow(limit, `${windowSeconds} s`),
      prefix: 'muuday:rl',
      analytics: true,
    })
    limiters.set(cacheKey, limiter)
  }
  return limiter
}

async function checkUpstashRateLimit({
  key,
  limit,
  windowSeconds,
}: RateLimitOptions): Promise<RateLimitResult | null> {
  try {
    const limiter = getLimiter(limit, windowSeconds)
    if (!limiter) return null

    const result = await limiter.limit(key)

    return {
      allowed: result.success,
      limit: result.limit,
      remaining: result.remaining,
      retryAfterSeconds: result.success
        ? 0
        : Math.max(1, Math.ceil((result.reset - Date.now()) / 1000)),
      source: 'upstash',
    }
  } catch {
    return null
  }
}

type MemoryBucket = {
  hits: number
  windowStartedAt: number
}

declare global {
  // eslint-disable-next-line no-var
  var __muudayRateLimitStore: Map<string, MemoryBucket> | undefined
  // eslint-disable-next-line no-var
  var __muudayRateLimitFallbackAlerts: Map<string, number> | undefined
}

function getStore() {
  if (!globalThis.__muudayRateLimitStore) {
    globalThis.__muudayRateLimitStore = new Map<string, MemoryBucket>()
  }
  return globalThis.__muudayRateLimitStore
}

function getFallbackAlertStore() {
  if (!globalThis.__muudayRateLimitFallbackAlerts) {
    globalThis.__muudayRateLimitFallbackAlerts = new Map<string, number>()
  }
  return globalThis.__muudayRateLimitFallbackAlerts
}

function getPresetNameFromKey(key: string) {
  const [preset] = key.split(':')
  return preset || 'unknown'
}

function reportMemoryFallback(options: RateLimitOptions) {
  const preset = getPresetNameFromKey(options.key)
  const now = Date.now()
  const alertStore = getFallbackAlertStore()
  const lastAlertAt = alertStore.get(preset) || 0

  if (now - lastAlertAt < MEMORY_FALLBACK_ALERT_INTERVAL_MS) {
    return
  }

  alertStore.set(preset, now)

  const message = `[rate-limit] Upstash unavailable; using in-memory fallback for preset="${preset}" (non-persistent across cold starts).`
  console.warn(message)
  Sentry.captureMessage('rate_limit_fallback_memory_active', {
    level: 'warning',
    tags: {
      area: 'rate_limit',
      source: 'memory',
      preset,
    },
    extra: {
      limit: options.limit,
      windowSeconds: options.windowSeconds,
    },
  })
}

function checkMemoryRateLimit({ key, limit, windowSeconds }: RateLimitOptions): RateLimitResult {
  const store = getStore()
  const now = Date.now()
  const windowMs = windowSeconds * 1000
  const existing = store.get(key)

  if (!existing || now - existing.windowStartedAt >= windowMs) {
    store.set(key, { hits: 1, windowStartedAt: now })
    return {
      allowed: true,
      limit,
      remaining: Math.max(0, limit - 1),
      retryAfterSeconds: 0,
      source: 'memory',
    }
  }

  existing.hits += 1
  store.set(key, existing)

  if (existing.hits <= limit) {
    return {
      allowed: true,
      limit,
      remaining: Math.max(0, limit - existing.hits),
      retryAfterSeconds: 0,
      source: 'memory',
    }
  }

  const retryAfterSeconds = Math.max(
    1,
    Math.ceil((windowMs - (now - existing.windowStartedAt)) / 1000),
  )
  return { allowed: false, limit, remaining: 0, retryAfterSeconds, source: 'memory' }
}

export async function checkRateLimit(options: RateLimitOptions): Promise<RateLimitResult> {
  const upstashResult = await checkUpstashRateLimit(options)
  if (upstashResult) return upstashResult
  reportMemoryFallback(options)
  return checkMemoryRateLimit(options)
}

export const RATE_LIMITS = {
  booking: { limit: 5, windowSeconds: 60 },
  bookingCreate: { limit: 6, windowSeconds: 120 },
  bookingManage: { limit: 10, windowSeconds: 60 },
  email: { limit: 10, windowSeconds: 60 },
  professionalProfile: { limit: 3, windowSeconds: 3600 },
  availability: { limit: 10, windowSeconds: 60 },
  waitlist: { limit: 10, windowSeconds: 300 },
  auth: { limit: 10, windowSeconds: 60 },
  authLogin: { limit: 12, windowSeconds: 300 },
  authSignup: { limit: 6, windowSeconds: 600 },
  authOAuth: { limit: 12, windowSeconds: 300 },
  stripeWebhook: { limit: 120, windowSeconds: 60 },
  supabaseDbWebhook: { limit: 240, windowSeconds: 60 },
  rewriteBio: { limit: 5, windowSeconds: 60 },
  profileMediaUpload: { limit: 10, windowSeconds: 60 },
  credentialsUpload: { limit: 10, windowSeconds: 60 },
  onboardingSave: { limit: 15, windowSeconds: 60 },
  onboardingSubmitReview: { limit: 5, windowSeconds: 300 },
  recomputeVisibility: { limit: 10, windowSeconds: 60 },
  stripeCheckout: { limit: 10, windowSeconds: 60 },
  calendarSync: { limit: 10, windowSeconds: 60 },
  calendarConnect: { limit: 10, windowSeconds: 60 },
  calendarDisconnect: { limit: 10, windowSeconds: 60 },
  openTerm: { limit: 20, windowSeconds: 60 },
  acceptTerm: { limit: 20, windowSeconds: 60 },
} as const

export async function rateLimit(
  preset: keyof typeof RATE_LIMITS,
  identifier: string,
): Promise<RateLimitResult> {
  const config = RATE_LIMITS[preset]
  return checkRateLimit({
    key: `${preset}:${identifier}`,
    ...config,
  })
}

#!/usr/bin/env node
/* eslint-disable no-console */

const { createClient } = require('@supabase/supabase-js')
const { existsSync, readFileSync } = require('fs')
const { resolve } = require('path')

function loadLocalEnvFile(fileName) {
  const envPath = resolve(process.cwd(), fileName)
  if (!existsSync(envPath)) return
  const content = readFileSync(envPath, 'utf-8')
  for (const rawLine of content.split('\n')) {
    const line = rawLine.trim()
    if (!line || line.startsWith('#')) continue
    const idx = line.indexOf('=')
    if (idx <= 0) continue
    const key = line.slice(0, idx).trim()
    const value = line.slice(idx + 1).trim()
    if (!process.env[key]) process.env[key] = value
  }
}

loadLocalEnvFile('.env.local')
loadLocalEnvFile('.env')

const SUPABASE_URL = process.env.NEXT_PUBLIC_SUPABASE_URL
const SUPABASE_ANON_KEY = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY

const USER_A_EMAIL = process.env.RLS_A_EMAIL || process.env.E2E_USER_EMAIL
const USER_A_PASSWORD = process.env.RLS_A_PASSWORD || process.env.E2E_USER_PASSWORD
const USER_B_EMAIL = process.env.RLS_B_EMAIL || process.env.E2E_PROFESSIONAL_EMAIL
const USER_B_PASSWORD = process.env.RLS_B_PASSWORD || process.env.E2E_PROFESSIONAL_PASSWORD
const SAMPLE_BOOKING_ID = process.env.RLS_SAMPLE_BOOKING_ID || null
const SAMPLE_PAYMENT_ID = process.env.RLS_SAMPLE_PAYMENT_ID || null
const SAMPLE_HIDDEN_REVIEW_ID = process.env.RLS_SAMPLE_HIDDEN_REVIEW_ID || null
const SAMPLE_MESSAGE_ID = process.env.RLS_SAMPLE_MESSAGE_ID || null

function fail(message) {
  console.error(`\n[rls-audit] FAIL: ${message}`)
  process.exit(1)
}

function warn(message) {
  console.warn(`[rls-audit] WARN: ${message}`)
}

function info(message) {
  console.log(`[rls-audit] ${message}`)
}

function makeClient() {
  return createClient(SUPABASE_URL, SUPABASE_ANON_KEY, {
    auth: { autoRefreshToken: false, persistSession: false, detectSessionInUrl: false },
  })
}

async function signIn(label, email, password) {
  const client = makeClient()
  const { data, error } = await client.auth.signInWithPassword({ email, password })
  if (error || !data?.user) {
    fail(`${label}: login failed (${error?.message || 'unknown error'})`)
  }
  info(`${label}: logged in as ${data.user.id}`)
  return { client, userId: data.user.id }
}

async function getProfessionalIdForUser(client, userId) {
  const { data, error } = await client
    .from('professionals')
    .select('id')
    .eq('user_id', userId)
    .limit(1)
    .maybeSingle()
  if (error) return null
  return data?.id || null
}

async function verifyOwnerCanRead(ownerClient, table, rowId) {
  const { data, error } = await ownerClient
    .from(table)
    .select('id')
    .eq('id', rowId)
    .limit(1)
  if (error) {
    return { ok: false, reason: `owner read error: ${error.message}` }
  }
  return { ok: Array.isArray(data) && data.length > 0, reason: 'owner row not visible' }
}

async function verifyCrossReadBlocked(actorClient, table, rowId) {
  const { data, error } = await actorClient
    .from(table)
    .select('id')
    .eq('id', rowId)
    .limit(1)

  if (error) {
    const message = String(error.message || '').toLowerCase()
    const code = String(error.code || '')
    if (
      code === 'PGRST205' ||
      code === '42P01' ||
      message.includes('could not find the table') ||
      message.includes('relation') && message.includes('does not exist')
    ) {
      return { ok: false, skipped: true, reason: 'table not found' }
    }
    return { ok: true, blocked: true, reason: `query blocked/error (${error.message})` }
  }

  const leaked = Array.isArray(data) && data.length > 0
  return leaked
    ? { ok: false, blocked: false, reason: 'row leaked in cross-user direct ID query' }
    : { ok: true, blocked: true, reason: 'no rows returned' }
}

async function findBookingSample(ownerClient, ownerProfessionalId, userAId) {
  if (!ownerProfessionalId) return null
  const { data, error } = await ownerClient
    .from('bookings')
    .select('id,user_id')
    .eq('professional_id', ownerProfessionalId)
    .neq('user_id', userAId)
    .limit(1)
  if (error || !data?.length) return null
  return data[0].id
}

async function findPaymentSample(ownerClient, ownerProfessionalId, userAId) {
  if (!ownerProfessionalId) return null
  const { data, error } = await ownerClient
    .from('payments')
    .select('id,user_id')
    .eq('professional_id', ownerProfessionalId)
    .neq('user_id', userAId)
    .limit(1)
  if (error || !data?.length) return null
  return data[0].id
}

async function findHiddenReviewSample(ownerClient, ownerUserId) {
  const { data, error } = await ownerClient
    .from('reviews')
    .select('id')
    .eq('user_id', ownerUserId)
    .eq('is_visible', false)
    .limit(1)
  if (error || !data?.length) return null
  return data[0].id
}

async function findMessageSample(ownerClient, ownerUserId, userAId) {
  // Current schema uses receiver_id, but keep recipient_id fallback for legacy datasets.
  const primary = await ownerClient
    .from('messages')
    .select('id,sender_id,receiver_id')
    .or(`sender_id.eq.${ownerUserId},receiver_id.eq.${ownerUserId}`)
    .neq('sender_id', userAId)
    .neq('receiver_id', userAId)
    .limit(1)

  const primaryError = primary.error
  if (!primaryError) {
    return { id: primary.data?.[0]?.id || null, missingTable: false }
  }

  const primaryCode = String(primaryError.code || '')
  const primaryMessage = String(primaryError.message || '').toLowerCase()
  if (
    primaryCode === 'PGRST205' ||
    primaryCode === '42P01' ||
    primaryMessage.includes('could not find the table') ||
    (primaryMessage.includes('relation') && primaryMessage.includes('does not exist'))
  ) {
    return { id: null, missingTable: true }
  }

  // If receiver_id is missing on older schema, retry against recipient_id.
  if (!primaryMessage.includes('receiver_id')) {
    return { id: null, missingTable: false }
  }

  const fallback = await ownerClient
    .from('messages')
    .select('id,sender_id,recipient_id')
    .or(`sender_id.eq.${ownerUserId},recipient_id.eq.${ownerUserId}`)
    .neq('sender_id', userAId)
    .neq('recipient_id', userAId)
    .limit(1)

  if (fallback.error) {
    const fallbackCode = String(fallback.error.code || '')
    const fallbackMessage = String(fallback.error.message || '').toLowerCase()
    if (
      fallbackCode === 'PGRST205' ||
      fallbackCode === '42P01' ||
      fallbackMessage.includes('could not find the table') ||
      (fallbackMessage.includes('relation') && fallbackMessage.includes('does not exist'))
    ) {
      return { id: null, missingTable: true }
    }
    return { id: null, missingTable: false }
  }

  return { id: fallback.data?.[0]?.id || null, missingTable: false }
}

async function run() {
  if (!SUPABASE_URL || !SUPABASE_ANON_KEY) {
    fail('Missing NEXT_PUBLIC_SUPABASE_URL or NEXT_PUBLIC_SUPABASE_ANON_KEY.')
  }
  if (!USER_A_EMAIL || !USER_A_PASSWORD || !USER_B_EMAIL || !USER_B_PASSWORD) {
    fail('Missing test credentials. Set RLS_A_EMAIL/RLS_A_PASSWORD and RLS_B_EMAIL/RLS_B_PASSWORD (or E2E_* fallbacks).')
  }

  info('Starting direct API RLS isolation audit...')

  const actorA = await signIn('user_a', USER_A_EMAIL, USER_A_PASSWORD)
  const actorB = await signIn('user_b', USER_B_EMAIL, USER_B_PASSWORD)

  const bProfessionalId = await getProfessionalIdForUser(actorB.client, actorB.userId)

  const checks = []

  const bookingId = SAMPLE_BOOKING_ID || await findBookingSample(actorB.client, bProfessionalId, actorA.userId)
  if (bookingId) {
    checks.push({ table: 'bookings', id: bookingId })
  } else {
    warn('No suitable booking sample found for cross-user test.')
  }

  const paymentId = SAMPLE_PAYMENT_ID || await findPaymentSample(actorB.client, bProfessionalId, actorA.userId)
  if (paymentId) {
    checks.push({ table: 'payments', id: paymentId })
  } else {
    warn('No suitable payment sample found for cross-user test.')
  }

  const hiddenReviewId = SAMPLE_HIDDEN_REVIEW_ID || await findHiddenReviewSample(actorB.client, actorB.userId)
  if (hiddenReviewId) {
    checks.push({ table: 'reviews', id: hiddenReviewId })
  } else {
    warn('No hidden review sample found. Hidden-review isolation check skipped.')
  }

  const messageSample = SAMPLE_MESSAGE_ID
    ? { id: SAMPLE_MESSAGE_ID, missingTable: false }
    : await findMessageSample(actorB.client, actorB.userId, actorA.userId)
  if (messageSample.missingTable) {
    warn('messages table not found. Messaging RLS check skipped.')
  } else if (messageSample.id) {
    checks.push({ table: 'messages', id: messageSample.id })
  } else {
    warn('No suitable message sample found for cross-user test.')
  }

  if (checks.length === 0) {
    warn('No executable checks found from sample data. Provide richer fixtures and rerun.')
    process.exit(2)
  }

  let failures = 0
  for (const check of checks) {
    const ownerCanRead = await verifyOwnerCanRead(actorB.client, check.table, check.id)
    if (!ownerCanRead.ok) {
      warn(`${check.table}: skipped (owner validation failed: ${ownerCanRead.reason})`)
      continue
    }

    const crossRead = await verifyCrossReadBlocked(actorA.client, check.table, check.id)
    if (crossRead.skipped) {
      warn(`${check.table}: skipped (${crossRead.reason})`)
      continue
    }
    if (!crossRead.ok) {
      failures += 1
      console.error(`[rls-audit] LEAK ${check.table} id=${check.id}: ${crossRead.reason}`)
      continue
    }
    info(`PASS ${check.table} id=${check.id}: ${crossRead.reason}`)
  }

  if (failures > 0) {
    fail(`${failures} cross-user isolation check(s) failed.`)
  }

  info('All executed cross-user isolation checks passed.')
}

run().catch((error) => {
  fail(error?.message || String(error))
})

#!/usr/bin/env node
/* eslint-disable no-console */

const fs = require('fs')
const path = require('path')

function parseArgs(argv) {
  const args = {
    registerPath: 'docs/engineering/runbooks/secrets-rotation-register.json',
    jsonOut: null,
  }

  for (let i = 2; i < argv.length; i += 1) {
    const token = argv[i]
    if (token === '--register' && argv[i + 1]) {
      args.registerPath = argv[i + 1]
      i += 1
      continue
    }
    if (token === '--json-out' && argv[i + 1]) {
      args.jsonOut = argv[i + 1]
      i += 1
      continue
    }
  }

  return args
}

function loadRegister(filePath) {
  const abs = path.resolve(process.cwd(), filePath)
  if (!fs.existsSync(abs)) {
    throw new Error(`Rotation register not found: ${abs}`)
  }
  const payload = JSON.parse(fs.readFileSync(abs, 'utf8'))
  if (!Array.isArray(payload.secrets)) {
    throw new Error('Invalid register format: secrets[] missing')
  }
  return { abs, payload }
}

function normalize(name) {
  return String(name || '').trim().toUpperCase()
}

async function githubRequest(url, token) {
  const response = await fetch(url, {
    headers: {
      Authorization: `Bearer ${token}`,
      Accept: 'application/vnd.github+json',
      'X-GitHub-Api-Version': '2022-11-28',
      'User-Agent': 'muuday-secrets-sync-audit',
    },
  })

  if (!response.ok) {
    const text = await response.text()
    throw new Error(`GitHub API ${response.status}: ${text}`)
  }

  return response.json()
}

async function vercelRequest(url, token) {
  const response = await fetch(url, {
    headers: {
      Authorization: `Bearer ${token}`,
      Accept: 'application/json',
      'User-Agent': 'muuday-secrets-sync-audit',
    },
  })

  if (!response.ok) {
    const text = await response.text()
    throw new Error(`Vercel API ${response.status}: ${text}`)
  }

  return response.json()
}

async function listGithubSecrets(repo, token) {
  const names = new Set()
  let page = 1

  while (true) {
    const data = await githubRequest(`https://api.github.com/repos/${repo}/actions/secrets?per_page=100&page=${page}`, token)
    const secrets = Array.isArray(data.secrets) ? data.secrets : []
    for (const item of secrets) {
      names.add(normalize(item.name))
    }
    if (secrets.length < 100) break
    page += 1
  }

  return names
}

async function listVercelEnvKeys(projectId, token, teamId) {
  const keys = new Set()
  let next = null

  while (true) {
    const base = new URL(`https://api.vercel.com/v10/projects/${projectId}/env`)
    base.searchParams.set('decrypt', 'false')
    base.searchParams.set('limit', '100')
    if (teamId) base.searchParams.set('teamId', teamId)
    if (next) base.searchParams.set('since', String(next))

    const data = await vercelRequest(base.toString(), token)
    const envs = Array.isArray(data.envs) ? data.envs : []

    for (const item of envs) {
      if (item && item.key) {
        keys.add(normalize(item.key))
      }
    }

    const pagination = data.pagination || {}
    if (!pagination.next) break
    next = pagination.next
  }

  return keys
}

function secretCovered(secret, availableSet) {
  const options = [secret.name, ...(Array.isArray(secret.aliases) ? secret.aliases : [])]
    .map(normalize)
    .filter(Boolean)

  return options.some((opt) => availableSet.has(opt))
}

function ensureDir(filePath) {
  fs.mkdirSync(path.dirname(filePath), { recursive: true })
}

async function main() {
  const args = parseArgs(process.argv)
  const { abs, payload } = loadRegister(args.registerPath)

  const githubRepo = process.env.GITHUB_REPOSITORY
  const githubToken = process.env.GITHUB_TOKEN || process.env.GH_TOKEN
  const vercelProjectId = process.env.VERCEL_PROJECT_ID
  const vercelToken = process.env.VERCEL_TOKEN
  const vercelTeamId = process.env.VERCEL_TEAM_ID || null

  if (!githubRepo) throw new Error('Missing GITHUB_REPOSITORY env.')
  if (!githubToken) throw new Error('Missing GITHUB_TOKEN (or GH_TOKEN).')
  if (!vercelProjectId) throw new Error('Missing VERCEL_PROJECT_ID env.')
  if (!vercelToken) throw new Error('Missing VERCEL_TOKEN env.')

  const [githubSecrets, vercelKeys] = await Promise.all([
    listGithubSecrets(githubRepo, githubToken),
    listVercelEnvKeys(vercelProjectId, vercelToken, vercelTeamId),
  ])

  const rows = []
  for (const secret of payload.secrets) {
    const targets = Array.isArray(secret.sync_targets) ? secret.sync_targets.map((t) => String(t).toLowerCase()) : []
    const expectsGithub = targets.includes('github')
    const expectsVercel = targets.includes('vercel')

    const githubOk = !expectsGithub || secretCovered(secret, githubSecrets)
    const vercelOk = !expectsVercel || secretCovered(secret, vercelKeys)

    rows.push({
      name: secret.name,
      aliases: secret.aliases || [],
      expects_github: expectsGithub,
      expects_vercel: expectsVercel,
      github_present: githubOk,
      vercel_present: vercelOk,
      status: githubOk && vercelOk ? 'ok' : 'missing',
    })
  }

  const missing = rows.filter((row) => row.status === 'missing')

  console.log(`[secrets-sync] Register: ${abs}`)
  console.log(`[secrets-sync] Repo: ${githubRepo}`)
  console.log(`[secrets-sync] Vercel project: ${vercelProjectId}`)
  console.log('')
  console.log('name | github | vercel | status')
  console.log('--- | --- | --- | ---')
  for (const row of rows) {
    const g = row.expects_github ? (row.github_present ? 'present' : 'missing') : 'n/a'
    const v = row.expects_vercel ? (row.vercel_present ? 'present' : 'missing') : 'n/a'
    console.log(`${row.name} | ${g} | ${v} | ${row.status}`)
  }

  if (args.jsonOut) {
    const outAbs = path.resolve(process.cwd(), args.jsonOut)
    ensureDir(outAbs)
    fs.writeFileSync(
      outAbs,
      JSON.stringify(
        {
          checked_at_utc: new Date().toISOString(),
          register_path: abs,
          github_repository: githubRepo,
          vercel_project_id: vercelProjectId,
          missing_count: missing.length,
          rows,
        },
        null,
        2,
      ),
      'utf8',
    )
    console.log(`\n[secrets-sync] JSON report written: ${outAbs}`)
  }

  if (missing.length > 0) {
    const names = missing.map((row) => row.name).join(', ')
    throw new Error(`Secrets missing in sync targets: ${names}`)
  }
}

main().catch((error) => {
  console.error(`[secrets-sync] ERROR: ${error.message}`)
  process.exit(1)
})

#!/usr/bin/env node
/* eslint-disable no-console */

const fs = require('fs')
const path = require('path')

function parseArgs(argv) {
  const args = {
    registerPath: 'docs/engineering/runbooks/secrets-rotation-register.json',
    warnWindowDays: 14,
    failOn: ['overdue'],
    jsonOut: null,
  }

  for (let i = 2; i < argv.length; i += 1) {
    const token = argv[i]
    if (token === '--register' && argv[i + 1]) {
      args.registerPath = argv[i + 1]
      i += 1
      continue
    }
    if (token === '--warn-window-days' && argv[i + 1]) {
      args.warnWindowDays = Number(argv[i + 1])
      i += 1
      continue
    }
    if (token === '--fail-on' && argv[i + 1]) {
      args.failOn = argv[i + 1].split(',').map((s) => s.trim()).filter(Boolean)
      i += 1
      continue
    }
    if (token === '--json-out' && argv[i + 1]) {
      args.jsonOut = argv[i + 1]
      i += 1
      continue
    }
  }

  return args
}

function parseISODate(value) {
  if (!value) return null
  const d = new Date(`${value}T00:00:00.000Z`)
  return Number.isNaN(d.getTime()) ? null : d
}

function formatDate(d) {
  return d.toISOString().slice(0, 10)
}

function addDays(date, days) {
  const ms = date.getTime() + days * 24 * 60 * 60 * 1000
  return new Date(ms)
}

function daysBetweenUTC(fromDate, toDate) {
  const from = Date.UTC(fromDate.getUTCFullYear(), fromDate.getUTCMonth(), fromDate.getUTCDate())
  const to = Date.UTC(toDate.getUTCFullYear(), toDate.getUTCMonth(), toDate.getUTCDate())
  return Math.floor((to - from) / (24 * 60 * 60 * 1000))
}

function loadRegister(filePath) {
  const abs = path.resolve(process.cwd(), filePath)
  if (!fs.existsSync(abs)) {
    throw new Error(`Rotation register not found: ${abs}`)
  }
  const raw = fs.readFileSync(abs, 'utf8')
  const parsed = JSON.parse(raw)
  if (!Array.isArray(parsed.secrets)) {
    throw new Error('Invalid register format: secrets[] missing')
  }
  return { abs, data: parsed }
}

function evaluateSecret(secret, today, warnWindowDays) {
  const cadence = Number(secret.cadence_days)
  if (!Number.isFinite(cadence) || cadence <= 0) {
    return {
      ...secret,
      status: 'invalid',
      days_until_due: null,
      computed_next_due_at: null,
      reason: 'invalid_cadence',
    }
  }

  const rotatedAt = parseISODate(secret.last_rotated_at)
  if (!rotatedAt) {
    return {
      ...secret,
      status: 'baseline_missing',
      days_until_due: null,
      computed_next_due_at: null,
      reason: 'missing_last_rotated_at',
    }
  }

  const explicitDue = parseISODate(secret.next_due_at)
  const dueAt = explicitDue || addDays(rotatedAt, cadence)
  const daysUntilDue = daysBetweenUTC(today, dueAt)

  let status = 'healthy'
  if (daysUntilDue < 0) {
    status = 'overdue'
  } else if (daysUntilDue <= warnWindowDays) {
    status = 'due_soon'
  }

  return {
    ...secret,
    status,
    days_until_due: daysUntilDue,
    computed_next_due_at: formatDate(dueAt),
    reason: explicitDue ? 'explicit_next_due_at' : 'derived_from_cadence',
  }
}

function printSummary(evaluated, warnWindowDays) {
  console.log(`[secrets-rotation] Audit date (UTC): ${formatDate(new Date())}`)
  console.log(`[secrets-rotation] Warn window: ${warnWindowDays} days`)
  console.log('')

  const counts = evaluated.reduce((acc, row) => {
    acc[row.status] = (acc[row.status] || 0) + 1
    return acc
  }, {})

  const statusOrder = ['overdue', 'due_soon', 'baseline_missing', 'healthy', 'invalid']
  for (const key of statusOrder) {
    if (counts[key]) {
      console.log(`[secrets-rotation] ${key}: ${counts[key]}`)
    }
  }

  console.log('')
  console.log('name | status | last_rotated_at | next_due_at | days_until_due')
  console.log('--- | --- | --- | --- | ---')

  for (const row of evaluated) {
    const days = row.days_until_due === null ? '' : String(row.days_until_due)
    console.log(
      `${row.name} | ${row.status} | ${row.last_rotated_at || ''} | ${row.computed_next_due_at || row.next_due_at || ''} | ${days}`,
    )
  }
}

function shouldFail(evaluated, failOn) {
  const failSet = new Set(failOn)
  return evaluated.some((row) => failSet.has(row.status))
}

function ensureDir(filePath) {
  const dir = path.dirname(filePath)
  fs.mkdirSync(dir, { recursive: true })
}

function main() {
  const args = parseArgs(process.argv)
  const { abs, data } = loadRegister(args.registerPath)

  const now = new Date()
  const today = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate()))
  const evaluated = data.secrets.map((secret) => evaluateSecret(secret, today, args.warnWindowDays))

  printSummary(evaluated, args.warnWindowDays)

  if (args.jsonOut) {
    const outAbs = path.resolve(process.cwd(), args.jsonOut)
    ensureDir(outAbs)
    const payload = {
      checked_at_utc: new Date().toISOString(),
      register_path: abs,
      warn_window_days: args.warnWindowDays,
      fail_on: args.failOn,
      summary: evaluated.reduce((acc, row) => {
        acc[row.status] = (acc[row.status] || 0) + 1
        return acc
      }, {}),
      rows: evaluated,
    }
    fs.writeFileSync(outAbs, JSON.stringify(payload, null, 2), 'utf8')
    console.log(`\n[secrets-rotation] JSON report written: ${outAbs}`)
  }

  if (shouldFail(evaluated, args.failOn)) {
    console.error(`\n[secrets-rotation] Failed due to statuses in fail-on set: ${args.failOn.join(', ')}`)
    process.exit(1)
  }
}

try {
  main()
} catch (error) {
  console.error(`[secrets-rotation] ERROR: ${error.message}`)
  process.exit(1)
}

#!/usr/bin/env node
/* eslint-disable no-console */

const fs = require('fs')
const path = require('path')

function parseArgs(argv) {
  const args = {
    baseUrl: process.env.ONBOARDING_SMOKE_BASE_URL || process.env.E2E_BASE_URL || 'http://localhost:3000',
    fixturePath: 'scripts/ops/onboarding-api-fixtures.json',
    jsonOut: null,
    timeoutMs: Number(process.env.ONBOARDING_SMOKE_TIMEOUT_MS || '30000'),
    cookie: process.env.ONBOARDING_SMOKE_COOKIE || '',
    bearer: process.env.ONBOARDING_SMOKE_BEARER || '',
    failOnSkipped: false,
    failOnNetworkError: true,
    listCases: false,
    help: false,
  }

  for (let i = 2; i < argv.length; i += 1) {
    const token = argv[i]
    if ((token === '--base-url' || token === '--baseUrl') && argv[i + 1]) {
      args.baseUrl = argv[i + 1]
      i += 1
      continue
    }
    if ((token === '--fixtures' || token === '--fixture') && argv[i + 1]) {
      args.fixturePath = argv[i + 1]
      i += 1
      continue
    }
    if (token === '--json-out' && argv[i + 1]) {
      args.jsonOut = argv[i + 1]
      i += 1
      continue
    }
    if (token === '--timeout-ms' && argv[i + 1]) {
      args.timeoutMs = Number(argv[i + 1])
      i += 1
      continue
    }
    if (token === '--cookie' && argv[i + 1]) {
      args.cookie = argv[i + 1]
      i += 1
      continue
    }
    if (token === '--bearer' && argv[i + 1]) {
      args.bearer = argv[i + 1]
      i += 1
      continue
    }
    if (token === '--fail-on-skipped') {
      args.failOnSkipped = true
      continue
    }
    if (token === '--allow-network-errors') {
      args.failOnNetworkError = false
      continue
    }
    if (token === '--list-cases') {
      args.listCases = true
      continue
    }
    if (token === '--help' || token === '-h') {
      args.help = true
      continue
    }
  }

  return args
}

function printHelp() {
  console.log('Usage: node scripts/ops/smoke-onboarding-api.cjs [options]')
  console.log('')
  console.log('Options:')
  console.log('  --base-url <url>         Target base URL (default: ONBOARDING_SMOKE_BASE_URL || E2E_BASE_URL || http://localhost:3000)')
  console.log('  --fixture <path>         Fixture JSON path (default: scripts/ops/onboarding-api-fixtures.json)')
  console.log('  --json-out <path>        Optional JSON report output')
  console.log('  --timeout-ms <number>    Request timeout in ms (default: 30000)')
  console.log('  --cookie <value>         Session cookie for authenticated cases')
  console.log('  --bearer <token>         Bearer token for authenticated cases')
  console.log('  --list-cases             Print fixture case IDs and exit')
  console.log('  --fail-on-skipped        Exit non-zero when any case is skipped')
  console.log('  --allow-network-errors   Do not fail process on request/network errors')
  console.log('  --help, -h               Show this help')
  console.log('')
  console.log('Notes:')
  console.log('  - Unauthenticated guard cases run by default.')
  console.log('  - Authenticated cases require --cookie or --bearer (or ONBOARDING_SMOKE_COOKIE / ONBOARDING_SMOKE_BEARER).')
}

function ensureDir(filePath) {
  fs.mkdirSync(path.dirname(filePath), { recursive: true })
}

function loadFixture(fixturePath) {
  const abs = path.resolve(process.cwd(), fixturePath)
  if (!fs.existsSync(abs)) {
    throw new Error(`Fixture file not found: ${abs}`)
  }
  const parsed = JSON.parse(fs.readFileSync(abs, 'utf8'))
  if (!Array.isArray(parsed.cases) || parsed.cases.length === 0) {
    throw new Error('Invalid fixture format: expected non-empty cases[]')
  }
  return { abs, cases: parsed.cases }
}

function resolveUrl(baseUrl, routePath) {
  return new URL(routePath, baseUrl.endsWith('/') ? baseUrl : `${baseUrl}/`).toString()
}

function hasPath(value, dottedPath) {
  const keys = dottedPath.split('.').filter(Boolean)
  let current = value
  for (const key of keys) {
    if (!current || typeof current !== 'object' || !(key in current)) {
      return false
    }
    current = current[key]
  }
  return true
}

function pickRequiredPaths(testCase, status) {
  const paths = []
  if (Array.isArray(testCase.requiredJsonPaths)) {
    paths.push(...testCase.requiredJsonPaths)
  }
  const byStatus = testCase.requiredJsonPathsWhenStatus || {}
  const exact = byStatus[String(status)]
  if (Array.isArray(exact)) {
    paths.push(...exact)
  }
  return Array.from(new Set(paths))
}

function makeHeaders(testCase, args) {
  const headers = {
    Accept: 'application/json',
  }
  const needsAuth = String(testCase.auth || 'none') !== 'none'
  if (needsAuth) {
    if (args.cookie) headers.Cookie = args.cookie
    if (args.bearer) headers.Authorization = `Bearer ${args.bearer}`
  }
  if (String(testCase.bodyType || '').toLowerCase() === 'json') {
    headers['Content-Type'] = 'application/json'
  }
  return headers
}

function makeBody(testCase) {
  const bodyType = String(testCase.bodyType || '').toLowerCase()
  if (bodyType === 'json') {
    return JSON.stringify(testCase.jsonBody || {})
  }
  if (bodyType === 'multipart') {
    const form = new FormData()
    const fields = Array.isArray(testCase.multipartFields) ? testCase.multipartFields : []
    for (const field of fields) {
      if (!field || !field.name) continue
      form.append(String(field.name), String(field.value || ''))
    }
    return form
  }
  return undefined
}

async function executeCase(testCase, args) {
  const requiresAuth = String(testCase.auth || 'none') !== 'none'
  const hasAuth = Boolean(args.cookie || args.bearer)
  if (requiresAuth && !hasAuth) {
    return {
      id: testCase.id,
      description: testCase.description || '',
      result: 'skipped',
      reason: 'missing_auth_context',
      request: {
        method: String(testCase.method || 'GET').toUpperCase(),
        path: testCase.path,
      },
    }
  }

  const method = String(testCase.method || 'GET').toUpperCase()
  const url = resolveUrl(args.baseUrl, String(testCase.path || '/'))
  const headers = makeHeaders(testCase, args)
  const body = makeBody(testCase)
  const expected = Array.isArray(testCase.expectedStatus) ? testCase.expectedStatus.map(Number) : []
  const timeout = Number.isFinite(args.timeoutMs) && args.timeoutMs > 0 ? args.timeoutMs : 30000
  const controller = new AbortController()
  const timeoutHandle = setTimeout(() => controller.abort(), timeout)

  const startedAt = new Date().toISOString()
  const begin = Date.now()

  try {
    const response = await fetch(url, {
      method,
      headers,
      body,
      signal: controller.signal,
    })

    const elapsedMs = Date.now() - begin
    const rawText = await response.text()
    const contentType = response.headers.get('content-type') || ''
    let parsed = null
    if (contentType.includes('application/json')) {
      try {
        parsed = rawText ? JSON.parse(rawText) : {}
      } catch {
        parsed = null
      }
    }

    const statusOk = expected.length === 0 || expected.includes(response.status)
    const requiredPaths = pickRequiredPaths(testCase, response.status)
    const missingPaths = []
    if (requiredPaths.length > 0) {
      for (const p of requiredPaths) {
        if (!parsed || !hasPath(parsed, p)) {
          missingPaths.push(p)
        }
      }
    }

    const assertions = []
    assertions.push({
      name: 'status',
      ok: statusOk,
      details: statusOk
        ? `status=${response.status}`
        : `expected one of [${expected.join(', ')}], got ${response.status}`,
    })
    assertions.push({
      name: 'required-json-paths',
      ok: missingPaths.length === 0,
      details:
        missingPaths.length === 0
          ? requiredPaths.length > 0
            ? `present [${requiredPaths.join(', ')}]`
            : 'no required paths'
          : `missing [${missingPaths.join(', ')}]`,
    })

    const failedAssertions = assertions.filter((a) => !a.ok)
    const result = failedAssertions.length > 0 ? 'failed' : 'passed'

    return {
      id: testCase.id,
      description: testCase.description || '',
      result,
      startedAt,
      elapsedMs,
      request: {
        method,
        path: testCase.path,
        url,
        auth: String(testCase.auth || 'none'),
      },
      response: {
        status: response.status,
        contentType,
        bodyPreview: rawText.slice(0, 400),
      },
      assertions,
    }
  } catch (error) {
    const elapsedMs = Date.now() - begin
    const message = error instanceof Error ? error.message : String(error)
    return {
      id: testCase.id,
      description: testCase.description || '',
      result: 'error',
      startedAt,
      elapsedMs,
      request: {
        method,
        path: testCase.path,
        url,
        auth: String(testCase.auth || 'none'),
      },
      error: message,
    }
  } finally {
    clearTimeout(timeoutHandle)
  }
}

function printSummary(results) {
  const counts = results.reduce(
    (acc, row) => {
      acc[row.result] = (acc[row.result] || 0) + 1
      return acc
    },
    { passed: 0, failed: 0, skipped: 0, error: 0 },
  )

  console.log(`[onboarding-api-smoke] passed=${counts.passed} failed=${counts.failed} skipped=${counts.skipped} error=${counts.error}`)
  console.log('')
  console.log('id | result | details')
  console.log('--- | --- | ---')
  for (const row of results) {
    let details = ''
    if (row.result === 'skipped') {
      details = row.reason || 'skipped'
    } else if (row.result === 'error') {
      details = row.error || 'request error'
    } else {
      details = `${row.request.method} ${row.request.path} -> ${row.response.status}`
      const failed = (row.assertions || []).filter((a) => !a.ok)
      if (failed.length > 0) {
        details = `${details}; ${failed.map((a) => a.details).join('; ')}`
      }
    }
    console.log(`${row.id} | ${row.result} | ${details}`)
  }
}

function shouldFail(results, args) {
  const hasFailed = results.some((row) => row.result === 'failed')
  const hasError = results.some((row) => row.result === 'error')
  const hasSkipped = results.some((row) => row.result === 'skipped')

  if (hasFailed) return true
  if (hasError && args.failOnNetworkError) return true
  if (hasSkipped && args.failOnSkipped) return true
  return false
}

async function main() {
  const args = parseArgs(process.argv)
  if (args.help) {
    printHelp()
    return
  }

  const { abs: fixtureAbs, cases } = loadFixture(args.fixturePath)
  if (args.listCases) {
    console.log(`[onboarding-api-smoke] fixture=${fixtureAbs}`)
    for (const item of cases) {
      console.log(`${item.id}: ${item.description || ''}`)
    }
    return
  }

  console.log(`[onboarding-api-smoke] baseUrl=${args.baseUrl}`)
  console.log(`[onboarding-api-smoke] fixture=${fixtureAbs}`)
  console.log(`[onboarding-api-smoke] auth=${args.cookie || args.bearer ? 'provided' : 'none'}`)
  console.log('')

  const results = []
  for (const testCase of cases) {
    const row = await executeCase(testCase, args)
    results.push(row)
  }

  printSummary(results)

  if (args.jsonOut) {
    const outAbs = path.resolve(process.cwd(), args.jsonOut)
    ensureDir(outAbs)
    fs.writeFileSync(
      outAbs,
      JSON.stringify(
        {
          checkedAtUtc: new Date().toISOString(),
          baseUrl: args.baseUrl,
          fixturePath: fixtureAbs,
          timeoutMs: args.timeoutMs,
          authProvided: Boolean(args.cookie || args.bearer),
          results,
        },
        null,
        2,
      ),
      'utf8',
    )
    console.log(`\n[onboarding-api-smoke] JSON report written: ${outAbs}`)
  }

  if (shouldFail(results, args)) {
    process.exit(1)
  }
}

main().catch((error) => {
  console.error(`[onboarding-api-smoke] ERROR: ${error.message}`)
  process.exit(1)
})

#!/usr/bin/env node
/* eslint-disable no-console */

const fs = require('fs')
const path = require('path')

function parseArgs(argv) {
  const args = {
    registerPath: 'docs/engineering/runbooks/secrets-rotation-register.json',
    secrets: [],
    date: new Date().toISOString().slice(0, 10),
    rotatedBy: 'operator',
    validationStatus: 'validated',
    note: null,
  }

  for (let i = 2; i < argv.length; i += 1) {
    const token = argv[i]
    if (token === '--register' && argv[i + 1]) {
      args.registerPath = argv[i + 1]
      i += 1
      continue
    }
    if (token === '--secrets' && argv[i + 1]) {
      args.secrets = argv[i + 1].split(',').map((s) => s.trim()).filter(Boolean)
      i += 1
      continue
    }
    if (token === '--date' && argv[i + 1]) {
      args.date = argv[i + 1]
      i += 1
      continue
    }
    if (token === '--by' && argv[i + 1]) {
      args.rotatedBy = argv[i + 1]
      i += 1
      continue
    }
    if (token === '--validation-status' && argv[i + 1]) {
      args.validationStatus = argv[i + 1]
      i += 1
      continue
    }
    if (token === '--note' && argv[i + 1]) {
      args.note = argv[i + 1]
      i += 1
      continue
    }
  }

  return args
}

function parseISODate(value) {
  const d = new Date(`${value}T00:00:00.000Z`)
  return Number.isNaN(d.getTime()) ? null : d
}

function addDays(date, days) {
  return new Date(date.getTime() + days * 24 * 60 * 60 * 1000)
}

function formatDate(d) {
  return d.toISOString().slice(0, 10)
}

function loadRegister(filePath) {
  const abs = path.resolve(process.cwd(), filePath)
  if (!fs.existsSync(abs)) {
    throw new Error(`Rotation register not found: ${abs}`)
  }
  const payload = JSON.parse(fs.readFileSync(abs, 'utf8'))
  if (!Array.isArray(payload.secrets)) {
    throw new Error('Invalid register format: secrets[] missing')
  }
  return { abs, payload }
}

function normalize(name) {
  return String(name || '').trim().toUpperCase()
}

function matches(entry, requested) {
  const target = normalize(requested)
  if (!target) return false
  if (normalize(entry.name) === target) return true
  if (Array.isArray(entry.aliases) && entry.aliases.some((alias) => normalize(alias) === target)) return true
  return false
}

function main() {
  const args = parseArgs(process.argv)
  if (args.secrets.length === 0) {
    throw new Error('Provide --secrets SECRET_A,SECRET_B')
  }

  const date = parseISODate(args.date)
  if (!date) {
    throw new Error('Invalid --date. Use YYYY-MM-DD.')
  }

  const { abs, payload } = loadRegister(args.registerPath)

  const unresolved = []
  for (const requested of args.secrets) {
    const entry = payload.secrets.find((item) => matches(item, requested))
    if (!entry) {
      unresolved.push(requested)
      continue
    }

    const cadence = Number(entry.cadence_days)
    if (!Number.isFinite(cadence) || cadence <= 0) {
      throw new Error(`Invalid cadence_days for ${entry.name}`)
    }

    entry.last_rotated_at = formatDate(date)
    entry.next_due_at = formatDate(addDays(date, cadence))
    entry.rotated_by = args.rotatedBy
    entry.validation_status = args.validationStatus
    if (args.note) {
      entry.notes = args.note
    }
  }

  if (unresolved.length > 0) {
    throw new Error(`Secrets not found in register: ${unresolved.join(', ')}`)
  }

  payload.updated_at = new Date().toISOString().slice(0, 10)
  fs.writeFileSync(abs, JSON.stringify(payload, null, 2) + '\n', 'utf8')

  console.log(`[secrets-rotation] Register updated: ${abs}`)
  console.log(`[secrets-rotation] Rotated date: ${formatDate(date)} | by: ${args.rotatedBy}`)
  console.log(`[secrets-rotation] Updated secrets: ${args.secrets.join(', ')}`)
}

try {
  main()
} catch (error) {
  console.error(`[secrets-rotation] ERROR: ${error.message}`)
  process.exit(1)
}

#!/usr/bin/env node
/* eslint-disable no-console */
const fs = require('fs')
const path = require('path')

function readFile(relativePath) {
  const fullPath = path.join(process.cwd(), relativePath)
  return fs.readFileSync(fullPath, 'utf8')
}

function extractArrayLiteral(source, constantName) {
  const pattern = new RegExp(
    `(?:export\\s+)?const\\s+${constantName}\\s*=\\s*\\[([\\s\\S]*?)\\]\\s+as\\s+const`,
  )
  const match = source.match(pattern)
  if (!match) throw new Error(`Could not find array literal for ${constantName}`)
  return Function(`"use strict"; return [${match[1]}]`)()
}

function extractObjectLiteral(source, constantName) {
  const startToken = `const ${constantName}`
  const start = source.indexOf(startToken)
  if (start < 0) throw new Error(`Could not find object constant ${constantName}`)
  const equalsIndex = source.indexOf('=', start)
  if (equalsIndex < 0) throw new Error(`Could not find '=' for ${constantName}`)
  const objectStart = source.indexOf('{', equalsIndex)
  if (objectStart < 0) throw new Error(`Could not find object literal start for ${constantName}`)

  let depth = 0
  let end = -1
  for (let i = objectStart; i < source.length; i += 1) {
    const char = source[i]
    if (char === '{') depth += 1
    if (char === '}') {
      depth -= 1
      if (depth === 0) {
        end = i
        break
      }
    }
  }
  if (end < 0) throw new Error(`Could not find object literal end for ${constantName}`)
  const objectLiteral = source.slice(objectStart, end + 1)
  return Function(`"use strict"; return (${objectLiteral})`)()
}

function assert(condition, message) {
  if (!condition) throw new Error(message)
}

function assertTransitionMap({ name, statuses, transitions, terminalStatuses, requiredEdges }) {
  const statusSet = new Set(statuses)

  statuses.forEach(status => {
    assert(
      Object.prototype.hasOwnProperty.call(transitions, status),
      `${name}: missing transition key for "${status}"`,
    )
  })

  Object.entries(transitions).forEach(([from, toList]) => {
    assert(statusSet.has(from), `${name}: unknown from-status "${from}"`)
    assert(Array.isArray(toList), `${name}: transition list for "${from}" is not an array`)
    toList.forEach(to => {
      assert(statusSet.has(to), `${name}: unknown to-status "${to}" in "${from}" transitions`)
    })
  })

  terminalStatuses.forEach(status => {
    assert(
      (transitions[status] || []).length === 0,
      `${name}: terminal status "${status}" must not allow outgoing transitions`,
    )
  })

  requiredEdges.forEach(([from, to]) => {
    assert(
      (transitions[from] || []).includes(to),
      `${name}: missing required transition "${from}" -> "${to}"`,
    )
  })
}

function run() {
  const bookingTypesSource = readFile('lib/booking/types.ts')
  const bookingSource = readFile('lib/booking/state-machine.ts')
  const bookingStatuses = extractArrayLiteral(bookingTypesSource, 'BOOKING_STATUSES')
  const bookingTransitions = extractObjectLiteral(bookingSource, 'ALLOWED_TRANSITIONS')

  assertTransitionMap({
    name: 'booking',
    statuses: bookingStatuses,
    transitions: bookingTransitions,
    terminalStatuses: ['cancelled', 'completed'],
    requiredEdges: [
      ['draft', 'pending_payment'],
      ['pending_payment', 'confirmed'],
      ['pending_confirmation', 'confirmed'],
      ['confirmed', 'completed'],
      ['confirmed', 'cancelled'],
      ['confirmed', 'no_show'],
    ],
  })

  const requestSource = readFile('lib/booking/request-booking-state-machine.ts')
  const requestStatuses = extractArrayLiteral(requestSource, 'REQUEST_BOOKING_STATUSES')
  const requestTransitions = extractObjectLiteral(
    requestSource,
    'ALLOWED_REQUEST_BOOKING_TRANSITIONS',
  )

  assertTransitionMap({
    name: 'request_booking',
    statuses: requestStatuses,
    transitions: requestTransitions,
    terminalStatuses: ['declined', 'expired', 'cancelled', 'converted'],
    requiredEdges: [
      ['open', 'offered'],
      ['open', 'cancelled'],
      ['offered', 'accepted'],
      ['offered', 'declined'],
      ['offered', 'converted'],
      ['accepted', 'converted'],
    ],
  })

  const recurringDeadlinesSource = readFile('lib/booking/recurring-deadlines.ts')
  assert(
    /RECURRING_RELEASE_DEADLINE_DAYS\s*=\s*7/.test(recurringDeadlinesSource),
    'recurring_deadlines: release deadline must be 7 days',
  )
  assert(
    /RECURRING_CHANGE_DEADLINE_DAYS\s*=\s*7/.test(recurringDeadlinesSource),
    'recurring_deadlines: change deadline must be 7 days',
  )
  assert(
    /RECURRING_PAUSE_DEADLINE_DAYS\s*=\s*7/.test(recurringDeadlinesSource),
    'recurring_deadlines: pause deadline must be 7 days',
  )
  assert(
    recurringDeadlinesSource.includes('type RecurringDeadlineDecision') &&
      recurringDeadlinesSource.includes('reason_code') &&
      recurringDeadlinesSource.includes('deadline_at_utc'),
    'recurring_deadlines: decision type must expose allowed/reason_code/deadline_at_utc',
  )

  const onboardingGatesSource = readFile('lib/professional/onboarding-gates.ts')
  assert(
    onboardingGatesSource.includes('export function evaluateOnboardingGates('),
    'onboarding_gates: evaluateOnboardingGates must exist as canonical gate evaluator',
  )
  assert(
    onboardingGatesSource.includes('return evaluateOnboardingGates(snapshot)'),
    'onboarding_gates: compatibility wrapper must delegate to evaluateOnboardingGates',
  )

  console.log('State machine validation passed.')
}

try {
  run()
} catch (error) {
  console.error('State machine validation failed.')
  console.error(error instanceof Error ? error.message : String(error))
  process.exit(1)
}

#!/usr/bin/env node
/* eslint-disable no-console */
const fs = require('node:fs')
const path = require('node:path')

function loadEnvFile(filePath) {
  if (!fs.existsSync(filePath)) return
  const lines = fs.readFileSync(filePath, 'utf8').split(/\r?\n/)
  for (const rawLine of lines) {
    const line = rawLine.trim()
    if (!line || line.startsWith('#')) continue
    const index = line.indexOf('=')
    if (index <= 0) continue
    const key = line.slice(0, index).trim()
    const value = line.slice(index + 1).trim()
    if (!process.env[key]) process.env[key] = value
  }
}

function normalizeUrl(urlValue) {
  return (urlValue || '').trim().replace(/^["']|["']$/g, '')
}

function parseConnectionUrl(name, rawValue) {
  const value = normalizeUrl(rawValue)
  if (!value) return null
  let parsed
  try {
    parsed = new URL(value)
  } catch (error) {
    throw new Error(`${name} is not a valid URL.`)
  }

  if (parsed.protocol !== 'postgresql:' && parsed.protocol !== 'postgres:') {
    throw new Error(`${name} must use postgres/postgresql protocol.`)
  }
  return parsed
}

function portOrDefault(parsed, defaultPort) {
  return parsed.port ? Number(parsed.port) : defaultPort
}

function main() {
  const root = process.cwd()
  loadEnvFile(path.join(root, '.env.local'))
  loadEnvFile(path.join(root, '.env'))
  loadEnvFile(path.join(root, '.env.production'))

  const poolerRaw =
    process.env.SUPABASE_DB_POOLER_URL ||
    process.env.DATABASE_URL ||
    process.env.POSTGRES_URL ||
    ''
  const directRaw =
    process.env.SUPABASE_DB_DIRECT_URL ||
    process.env.DATABASE_DIRECT_URL ||
    process.env.POSTGRES_PRISMA_URL ||
    ''

  const runtimeEnv = String(
    process.env.VERCEL_ENV || process.env.APP_ENV || process.env.NODE_ENV || '',
  ).toLowerCase()
  const requirePooler =
    process.env.REQUIRE_DB_POOLER === 'true' ||
    runtimeEnv === 'production'

  const pooler = parseConnectionUrl('SUPABASE_DB_POOLER_URL/DATABASE_URL', poolerRaw)
  if (!pooler) {
    if (requirePooler) {
      throw new Error(
        'Missing pooled DB connection string. Set SUPABASE_DB_POOLER_URL (or DATABASE_URL) to Supavisor port 6543.',
      )
    }
    console.log(
      '[db-pooling] INFO: pooled URL is not configured in local/dev environment. Production must set SUPABASE_DB_POOLER_URL.',
    )
    return
  }

  const poolerPort = portOrDefault(pooler, 5432)
  if (poolerPort !== 6543) {
    throw new Error(
      `Pooler URL must use port 6543 (Supavisor transaction mode). Found ${poolerPort}.`,
    )
  }

  const poolerHost = (pooler.hostname || '').toLowerCase()
  if (!poolerHost.includes('pooler') && !poolerHost.includes('supabase')) {
    console.warn(
      `[warn] Pooler host "${pooler.hostname}" does not look like a Supabase/Supavisor endpoint. Verify manually.`,
    )
  }

  const direct = parseConnectionUrl('SUPABASE_DB_DIRECT_URL/DATABASE_DIRECT_URL', directRaw)
  if (direct) {
    const directPort = portOrDefault(direct, 5432)
    if (directPort === 6543) {
      throw new Error(
        'Direct DB URL cannot use port 6543. Use direct postgres endpoint (typically 5432).',
      )
    }
  }

  console.log('[db-pooling] OK: pooled connection string is configured on port 6543.')
  if (direct) {
    console.log('[db-pooling] OK: direct connection string is separate from pooled URL.')
  } else {
    console.log(
      '[db-pooling] INFO: direct connection string not set (optional for migration/maintenance tooling).',
    )
  }
}

try {
  main()
} catch (error) {
  console.error(`[db-pooling] Failed: ${error instanceof Error ? error.message : String(error)}`)
  process.exit(1)
}
